export class EasyApplyWorkflowComponent {
  toggleJobFrame() {
    this.showJobFrame = !this.showJobFrame;
  }
  constructor(jobService, diceApi, coverLetterService) {
    this.jobService = jobService;
    this.diceApi = diceApi;
    this.coverLetterService = coverLetterService;
    this.currentJob = null;
    this.jobs = [];
    this.jobStats = {
      total: 0,
      pending: 0,
      applied: 0,
      skipped: 0
    };
    this.isLoading = false;
    this.coverLetterMode = null;
    this.generatedCoverLetter = '';
    this.savedCoverLetterPath = '';
    this.jobDescription = '';
    this.showReview = false;
    this.currentStep = 'cover-letter';
    this.decisionNotes = '';
    this.skipReason = '';
    this.showJobFrame = false;
    this.showSettings = false;
    this.geminiApiKey = '';
    this.destroy$ = new Subject();
  }
  ngOnInit() {
    this.subscribeToJobUpdates();
    this.loadGeminiApiKey();
    // If a job was pre-selected (e.g. from grid row click), use it directly
    const preSelected = this.jobService.getCurrentJob();
    if (preSelected) {
      this.resetWorkflow();
      this.currentJob = preSelected;
      this.fetchJobDescription(preSelected);
      this.updateStats();
    } else {
      this.loadJobs();
    }
  }
  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
  }
  loadJobs() {
    this.isLoading = true;
    this.diceApi.searchEasyApplyJobs().pipe(takeUntil(this.destroy$)).subscribe({
      next: jobs => {
        this.jobService.setJobs(jobs);
        this.nextJob();
        this.isLoading = false;
      },
      error: err => {
        console.error('Error loading jobs:', err);
        this.nextJob();
        this.isLoading = false;
      }
    });
  }
  subscribeToJobUpdates() {
    this.jobService.jobs$.pipe(takeUntil(this.destroy$)).subscribe(jobs => {
      this.jobs = jobs;
      this.updateStats();
    });
  }
  updateStats() {
    this.jobStats = this.jobService.getJobStats();
  }
  loadGeminiApiKey() {
    this.geminiApiKey = localStorage.getItem('gemini_api_key') || '';
  }
  nextJob() {
    this.resetWorkflow();
    const job = this.jobService.nextPendingJob();
    if (job) {
      this.currentJob = job;
      this.fetchJobDescription(job);
    }
  }
  resetWorkflow() {
    this.coverLetterMode = null;
    this.generatedCoverLetter = '';
    this.savedCoverLetterPath = '';
    this.showJobFrame = false;
    this.jobDescription = '';
    this.showReview = false;
    this.currentStep = 'cover-letter';
    this.decisionNotes = '';
    this.skipReason = '';
  }
  fetchJobDescription(job) {
    this.isLoading = true;
    this.diceApi.getJobDescription(job).pipe(takeUntil(this.destroy$)).subscribe({
      next: desc => {
        this.jobDescription = desc || 'Job description not available';
        this.isLoading = false;
      },
      error: () => {
        this.jobDescription = 'Could not fetch job description';
        this.isLoading = false;
      }
    });
  }
  selectCoverLetterMode(mode) {
    this.coverLetterMode = mode;
    if (mode === null) {
      this.currentStep = 'review';
      this.generatedCoverLetter = '';
    } else {
      this.generateCoverLetter(mode);
    }
  }
  generateCoverLetter(mode) {
    if (!this.currentJob) return;
    this.isLoading = true;
    this.savedCoverLetterPath = '';
    const saveAfterGenerate = letter => {
      this.generatedCoverLetter = letter;
      this.coverLetterService.saveCoverLetterAsTxt(this.currentJob, letter, mode).pipe(takeUntil(this.destroy$)).subscribe({
        next: savedPath => {
          this.savedCoverLetterPath = savedPath || '';
          this.isLoading = false;
        },
        error: () => {
          this.isLoading = false;
        }
      });
